'use client'

import { useState, useRef, useEffect } from 'react'
import { motion } from 'framer-motion'
import Image from 'next/image'
import { BadgeCheck, Play, Pause, MapPin, ExternalLink, Mail, Instagram, Twitter, Facebook, Youtube, Music2, MessageCircle } from 'lucide-react'
import { urlForImage } from '@/sanity/lib/image'

const socialIcons: any = {
  email: Mail,
  instagram: Instagram,
  tiktok: Music2,
  whatsapp: MessageCircle,
  youtube: Youtube,
  facebook: Facebook,
  twitter: Twitter,
  spotify: Music2,
}

export default function LinktreeView({ data }: { data: any }) {
  const [isPlaying, setIsPlaying] = useState(false)
  const audioRef = useRef<HTMLAudioElement | null>(null)

  useEffect(() => {
    if (data.backgroundMusic) {
      // Audio setup
    }
  }, [data.backgroundMusic])

  const togglePlay = () => {
    if (audioRef.current) {
      if (isPlaying) {
        audioRef.current.pause()
      } else {
        audioRef.current.play()
      }
      setIsPlaying(!isPlaying)
    }
  }

  // Theme classes
  const getThemeClasses = () => {
    switch(data.themeColor) {
      case 'dark': return { bg: 'bg-gray-900', text: 'text-white', textSub: 'text-white/70', cardBg: 'bg-white/15 backdrop-blur-md border-white/20' }
      case 'wtp-pink': return { bg: 'bg-[#fdbcd6]', text: 'text-gray-900', textSub: 'text-gray-700', cardBg: 'bg-white/40 backdrop-blur-md border-pink-200/40' }
      case 'gold': return { bg: 'bg-amber-100', text: 'text-amber-900', textSub: 'text-amber-700', cardBg: 'bg-white/40 backdrop-blur-md border-amber-200/40' }
      default: return { bg: 'bg-gray-50', text: 'text-gray-900', textSub: 'text-gray-500', cardBg: 'bg-gray-100/80 border-gray-200/60' }
    }
  }

  const theme = getThemeClasses()

  // Button shape
  const getButtonRadius = () => {
    if(data.buttonShape === 'rounded-none') return 'rounded-none'
    if(data.buttonShape === 'rounded-xl') return 'rounded-xl'
    return 'rounded-full'
  }

  // Button style
  const getButtonStyle = () => {
    const radius = getButtonRadius()
    if (data.buttonStyle === 'glass') {
      return `${radius} bg-white/15 backdrop-blur-md border border-white/20 shadow-lg text-inherit`
    } else if (data.buttonStyle === 'outline') {
      return `${radius} border-2 border-current bg-transparent`
    } else {
      return `${radius} bg-white text-gray-900 shadow-md`
    }
  }

  // Hover animation
  const getHoverAnimation = () => {
    if(data.buttonHoverAnimation === 'bounce') return { y: -4 }
    if(data.buttonHoverAnimation === 'pulse') return { scale: 1.03, boxShadow: '0 0 20px rgba(255,255,255,0.3)' }
    return { scale: 1.02 }
  }

  // Profile shape
  const getProfileShape = () => {
    if(data.profileShape === 'rounded-none') return 'rounded-none'
    if(data.profileShape === 'rounded-2xl') return 'rounded-2xl'
    return 'rounded-full'
  }

  // Verified badge color
  const getBadgeColor = () => {
    if(data.verifiedBadgeColor === 'gold') return 'text-yellow-400'
    if(data.verifiedBadgeColor === 'pink') return 'text-pink-400'
    if(data.verifiedBadgeColor === 'black') return 'text-gray-900'
    return 'text-blue-500'
  }

  // Badge color map
  const badgeColorMap: any = {
    merah: 'bg-red-500',
    hijau: 'bg-green-500',
    biru: 'bg-blue-500',
    kuning: 'bg-yellow-500',
  }

  // Separate portfolio links from regular links
  const portfolioLinks = data.links?.filter((l: any) => l.type === 'portfolio' && l.isActive) || []
  const regularLinks = data.links?.filter((l: any) => l.type !== 'portfolio') || []

  // Font family
  const fontClass = data.fontFamily === 'serif' ? 'font-serif' : data.fontFamily === 'mono' ? 'font-mono' : 'font-sans'

  return (
    <div className={`min-h-screen w-full relative overflow-hidden ${theme.bg} ${theme.text} ${fontClass}`}>
      
      {/* Background Image */}
      {data.backgroundImage && (
        <div className="fixed inset-0 z-0">
          <Image 
            src={urlForImage(data.backgroundImage).url()} 
            alt="" 
            fill 
            className="object-cover"
          />
          <div className="absolute inset-0 bg-black/40" />
        </div>
      )}

      {/* Scrollable Content */}
      <div className="relative z-10 max-w-lg mx-auto px-5 pt-8 pb-16 flex flex-col items-center">
        
        {/* ─── Header Banner ─── */}
        {data.headerBanner && (
          <motion.div 
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5 }}
            className={`w-full h-36 md:h-48 relative rounded-2xl overflow-hidden shadow-xl ${data.profileImage ? 'mb-0' : 'mb-6'}`}
          >
            <Image 
              src={urlForImage(data.headerBanner).url()} 
              alt="Banner" 
              fill 
              className="object-cover"
            />
          </motion.div>
        )}

        {/* ─── Profile Image ─── */}
        {data.profileImage && (
          <motion.div 
            initial={{ scale: 0, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            transition={{ type: "spring", stiffness: 200, damping: 18, delay: 0.15 }}
            className={`relative z-20 w-24 h-24 md:w-28 md:h-28 ${data.headerBanner ? '-mt-12' : 'mt-0'} shadow-xl border-[3px] border-white ${getProfileShape()} overflow-hidden`}
          >
            <Image 
              src={urlForImage(data.profileImage).url()} 
              alt={data.profileName || 'Profile'} 
              fill 
              className="object-cover"
            />
          </motion.div>
        )}

        {/* ─── Name + Badge + Location ─── */}
        <motion.div 
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.25, duration: 0.4 }}
          className="text-center mt-4 mb-2"
        >
          <h1 className="text-xl md:text-2xl font-bold flex items-center justify-center gap-1.5">
            {data.profileName}
            {data.verifiedBadge && (
              <BadgeCheck className={`w-5 h-5 ${getBadgeColor()} fill-current`} />
            )}
          </h1>
          
          {!data.hideLocation && data.location && (
            <p className={`flex items-center justify-center gap-1 text-xs mt-1 ${theme.textSub}`}>
              <MapPin className="w-3.5 h-3.5" /> {data.location}
            </p>
          )}
        </motion.div>

        {/* ─── Hero Text (Glassmorphism Card) ─── */}
        {data.heroText && (
          <motion.div 
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.35, duration: 0.4 }}
            className={`w-full mt-3 mb-6 px-5 py-4 rounded-xl border text-center text-sm leading-relaxed ${theme.cardBg}`}
          >
            {data.heroText}
          </motion.div>
        )}

        {/* ─── Top Social Icons ─── */}
        {data.socialPosition === 'top' && data.socialLinks?.length > 0 && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.4 }}
            className="flex flex-wrap justify-center gap-3 mb-6"
          >
            {data.socialLinks.map((social: any, idx: number) => {
              const Icon = socialIcons[social.platform] || ExternalLink
              return (
                <a 
                  key={idx} 
                  href={social.url} 
                  target="_blank" 
                  rel="noreferrer"
                  className="w-10 h-10 flex items-center justify-center bg-white/15 backdrop-blur-sm rounded-full hover:bg-white/30 transition-all duration-300"
                >
                  <Icon className="w-4 h-4" />
                </a>
              )
            })}
          </motion.div>
        )}

        {/* ─── Link Buttons ─── */}
        <div className="w-full space-y-3">
          {regularLinks.map((link: any, idx: number) => {
            if (!link.isActive) return null

            // Divider
            if (link.type === 'divider') {
              return (
                <motion.div 
                  key={link._key || idx} 
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  transition={{ delay: 0.1 * idx }}
                  className="flex items-center gap-3 py-3"
                >
                  <div className="h-px bg-current opacity-20 flex-1" />
                  <span className="text-xs font-bold uppercase tracking-[0.2em] opacity-60">{link.title}</span>
                  <div className="h-px bg-current opacity-20 flex-1" />
                </motion.div>
              )
            }

            return (
              <div key={link._key || idx} className="relative w-full">
                {/* Badge (Absolute Top Right - Sticking Out) */}
                {link.badgeText && (
                  <span className={`absolute -top-1.5 -right-1 z-30 text-[10px] font-bold px-2 py-0.5 rounded-md text-white shadow-md transform translate-x-1/4 -translate-y-1/4 ${badgeColorMap[link.badgeColor] || 'bg-red-500'}`}>
                    {link.badgeText}
                  </span>
                )}

                <motion.a
                  href={link.url}
                  target="_blank"
                  rel="noreferrer"
                  className={`relative w-full flex items-center justify-center min-h-[56px] px-14 py-3.5 mb-3 overflow-hidden transition-all duration-300 ${getButtonStyle()}`}
                  initial={{ opacity: 0, y: 15 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 0.08 * idx, duration: 0.35 }}
                  whileHover={getHoverAnimation()}
                  whileTap={{ scale: 0.97 }}
                >
                  {/* Shimmer highlight */}
                  {link.isHighlighted && (
                    <motion.div 
                      animate={{ x: ['-100%', '200%'] }} 
                      transition={{ repeat: Infinity, duration: 2.5, ease: "linear" }}
                      className="absolute inset-0 w-1/3 h-full bg-gradient-to-r from-transparent via-white/30 to-transparent skew-x-[-20deg] pointer-events-none"
                    />
                  )}

                  {/* Icon (Fixed Position on Left) */}
                  {link.icon && (
                    <div className="absolute left-4 top-1/2 -translate-y-1/2 w-9 h-9 rounded-lg overflow-hidden border border-current/10">
                      <Image src={urlForImage(link.icon).url()} alt="" fill className="object-cover" />
                    </div>
                  )}
                  
                  {/* Centered Title */}
                  <span className="font-semibold text-sm text-center z-10">{link.title}</span>
                </motion.a>
              </div>
            )
          })}
        </div>

        {/* ─── Portfolio Grid ─── */}
        {portfolioLinks.length > 0 && (
          <motion.div
            initial={{ opacity: 0, y: 15 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.5 }}
            className="w-full mt-6"
          >
            <h3 className="text-sm font-bold text-center mb-4 uppercase tracking-wider opacity-80">Our Portofolio</h3>
            <div className="grid grid-cols-2 gap-2.5">
              {portfolioLinks.map((link: any, idx: number) => (
                <a 
                  key={link._key || idx}
                  href={link.url}
                  target="_blank"
                  rel="noreferrer"
                  className="relative aspect-[4/5] rounded-xl overflow-hidden group"
                >
                  {link.icon && (
                    <Image 
                      src={urlForImage(link.icon).url()} 
                      alt={link.title || ''} 
                      fill 
                      className="object-cover transition-transform duration-500 group-hover:scale-110"
                    />
                  )}
                  <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-transparent to-transparent" />
                  <span className="absolute bottom-3 left-3 right-3 text-white text-xs font-semibold z-10">{link.title}</span>
                </a>
              ))}
            </div>
          </motion.div>
        )}
        
        {/* ─── Bottom Social Icons ─── */}
        {data.socialPosition === 'bottom' && data.socialLinks?.length > 0 && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.6 }}
            className="flex flex-wrap justify-center gap-3 mt-8"
          >
            {data.socialLinks.map((social: any, idx: number) => {
              const Icon = socialIcons[social.platform] || ExternalLink
              return (
                <a 
                  key={idx} 
                  href={social.url} 
                  target="_blank" 
                  rel="noreferrer"
                  className="w-10 h-10 flex items-center justify-center bg-white/15 backdrop-blur-sm rounded-full hover:bg-white/30 transition-all duration-300"
                >
                  <Icon className="w-4 h-4" />
                </a>
              )
            })}
          </motion.div>
        )}

        {/* ─── Footer ─── */}
        {data.footerText && (
          <motion.footer 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.7 }}
            className="mt-12 pb-6 text-xs font-bold uppercase tracking-[0.2em] opacity-50"
          >
            {data.footerText}
          </motion.footer>
        )}
      </div>
    </div>
  )
}
